namespace SiteInspector.Client.Services;

public interface IConnectivityService
{
    bool IsOnline { get; }
    event Action<bool>? OnConnectivityChanged;
    Task InitializeAsync();
}

public class ConnectivityService : IConnectivityService, IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await _js.InvokeAsync<IJSObjectReference>("import", "./js/connectivity.js");
        IsOnline = await _module.InvokeAsync<bool>("initialize", _dotNetRef);
    }

    [JSInvokable]
    public void OnStatusChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnConnectivityChanged?.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.InvokeVoidAsync("dispose");
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}
"}

{"path": "/tmp/sv-358f299904df49fba9b1537ac2701cb0/SiteInspector/SiteInspector.Client/Services/SyncService.cs", "file_text": "using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public interface ISyncService
{
    int PendingSyncCount { get; }
    bool IsSyncing { get; }
    event Action? OnSyncStateChanged;
    Task SyncAsync();
    Task RefreshPendingCountAsync();
}

public class SyncService : ISyncService
{
    private readonly IStorageService _storage;
    private readonly IConnectivityService _connectivity;
    private readonly HttpClient _http;

    public int PendingSyncCount { get; private set; }
    public bool IsSyncing { get; private set; }
    public event Action? OnSyncStateChanged;

    public SyncService(IStorageService storage, IConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;
        _connectivity.OnConnectivityChanged += OnConnectivityChanged;
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await SyncAsync();
        }
    }

    public async Task RefreshPendingCountAsync()
    {
        var unsynced = await _storage.GetUnsyncedInspectionsAsync();
        PendingSyncCount = unsynced.Count;
        OnSyncStateChanged?.Invoke();
    }

    public async Task SyncAsync()
    {
        if (IsSyncing || !_connectivity.IsOnline) return;

        IsSyncing = true;
        OnSyncStateChanged?.Invoke();

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkAsSyncedAsync(inspection.Id);
                    }
                }
                catch
                {
                    // Individual sync failure — continue with remaining items
                }
            }

            await RefreshPendingCountAsync();
        }
        finally
        {
            IsSyncing = false;
            OnSyncStateChanged?.Invoke();
        }
    }
}
"}

