const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

export async function initialize() {
    await openDb();
}

export async function getAllSites() {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('sites', 'readonly');
        const store = tx.objectStore('sites');
        const request = store.getAll();
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function saveSite(site) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('sites', 'readwrite');
        const store = tx.objectStore('sites');
        store.put(site);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

export async function deleteSite(siteId) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('sites', 'readwrite');
        const store = tx.objectStore('sites');
        store.delete(siteId);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

export async function getInspections(siteId) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        let request;
        if (siteId) {
            const index = store.index('siteId');
            request = index.getAll(siteId);
        } else {
            request = store.getAll();
        }
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function getInspection(inspectionId) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const request = store.get(inspectionId);
        request.onsuccess = () => resolve(request.result || null);
        request.onerror = () => reject(request.error);
    });
}

export async function saveInspection(inspection) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('inspections', 'readwrite');
        const store = tx.objectStore('inspections');
        store.put(inspection);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

export async function deleteInspection(inspectionId) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('inspections', 'readwrite');
        const store = tx.objectStore('inspections');
        store.delete(inspectionId);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

export async function getUnsyncedInspections() {
    const database = await openDb();
    return new Promise((resolve, reject) => {
        const tx = database.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const index = store.index('isSynced');
        const request = index.getAll(false);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function markAsSynced(inspectionId) {
    const database = await openDb();
    return new Promise((resolve, reject) => {
