@page "/"
@inject IStorageService Storage
@inject ISyncService Sync

<PageTitle>Site Inspector</PageTitle>

<div class="page-content">
    <div class="section-header">
        <h2>Construction Sites</h2>
        <button class="btn-add" @onclick="ShowAddSite">+ Add Site</button>
    </div>

    @if (_showAddForm)
    {
        <div class="card add-form">
            <input type="text" class="input" placeholder="Site name" @bind="_newSiteName" @bind:event="oninput" />
            <input type="text" class="input" placeholder="Address" @bind="_newSiteAddress" @bind:event="oninput" />
            <div class="form-actions">
                <button class="btn btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
                <button class="btn btn-secondary" @onclick="CancelAdd">Cancel</button>
            </div>
        </div>
    }

    @if (_sites.Count == 0 && !_showAddForm)
    {
        <div class="empty-state">
            <span class="empty-icon">🏗️</span>
            <p>No sites yet. Add your first construction site to begin inspections.</p>
        </div>
    }

    <div class="site-list">
        @foreach (var site in _sites)
        {
            <a href="/site/@site.Id" class="site-card">
                <div class="site-info">
                    <h3>@site.Name</h3>
                    <p>@site.Address</p>
                </div>
                <span class="chevron">›</span>
            </a>
        }
    </div>
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _sites = await Storage.GetSitesAsync();
        await Sync.RefreshPendingCountAsync();
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd()
    {
        _showAddForm = false;
        _newSiteName = "";
        _newSiteAddress = "";
    }

