{"file_text": "@page "/site/{SiteId}"
@inject IStorageService Storage
@inject NavigationManager Nav

<PageTitle>@_site?.Name</PageTitle>

<div class="page-content">
    <div class="section-header">
        <h2>@(_site?.Name ?? "Loading...")</h2>
        <button class="btn-add" @onclick="StartNewInspection">+ Inspect</button>
    </div>

    @if (_site is not null)
    {
        <p class="site-address">@_site.Address</p>
    }

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <span class="empty-icon">📋</span>
            <p>No inspections yet. Start a new inspection to create a safety checklist.</p>
        </div>
    }

    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.InspectionDate))
        {
            <a href="/inspection/@inspection.Id" class="inspection-card">
                <div class="inspection-info">
                    <div class="inspection-date">@inspection.InspectionDate.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</div>
                    <div class="inspection-meta">
                        <span class="status-badge @inspection.Status.ToString().ToLower()">@inspection.Status</span>
                        @{ var passed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass); }
                        @{ var total = inspection.ChecklistItems.Count; }
                        <span class="check-count">@passed/@total items</span>
                        @if (inspection.Photos.Count > 0)
                        {
                            <span class="photo-count">📷 @inspection.Photos.Count</span>
                        }
                        @if (!inspection.IsSynced)
                        {
                            <span class="unsynced-badge">⏳</span>
                        }
                    </div>
                </div>
                <span class="chevron">›</span>
            </a>
        }
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        var sites = await Storage.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Storage.GetInspectionsAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            ChecklistItems = ChecklistTemplateService.GetDefaultChecklist()
        };

        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }
}
