@page "/inspection/{InspectionId}"
@inject IStorageService Storage
@inject ISyncService Sync
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection</PageTitle>

<div class="inspection-page">
    @if (_inspection is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="tabs">
            <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
                Checklist
            </button>
            <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
                Photos (@_inspection.Photos.Count)
            </button>
            <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
                Notes
            </button>
        </div>

        @if (_activeTab == "checklist")
        {
            <div class="checklist-section">
                <div class="progress-bar">
                    <div class="progress-fill" style="width: @ProgressPercent%"></div>
                </div>
                <div class="progress-text">@CheckedCount / @_inspection.ChecklistItems.Count checked</div>

                @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
                {
                    <div class="category-group">
                        <h3 class="category-title">@category.Key</h3>
                        @foreach (var item in category)
                        {
                            <div class="checklist-item">
                                <div class="item-description">@item.Description</div>
                                <div class="item-buttons">
                                    <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                                </div>
                                @if (item.Result == CheckResult.Fail)
                                {
                                    <input type="text" class="item-note" placeholder="Add note about failure..."
                                           value="@item.Notes"
                                           @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                                }
                            </div>
                        }
                    </div>
                }
            </div>
        }
        else if (_activeTab == "photos")
        {
            <div class="photos-section">
                <label class="photo-upload-btn">
                    📷 Take / Add Photo
                    <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" />
                </label>

                @if (_inspection.Photos.Count == 0)
                {
                    <div class="empty-state">
                        <p>No photos attached. Tap above to add photos to this inspection.</p>
                    </div>
                }

                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos)
                    {
                        <div class="photo-card">
                            <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                            <input type="text" class="photo-caption" placeholder="Add caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                            <button class="photo-delete" @onclick="() => RemovePhoto(photo)">🗑️</button>
                        </div>
                    }
                </div>
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="notes-section">
                <textarea class="notes-input" placeholder="General inspection notes..."
                          @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveDebounced"></textarea>
            </div>
        }

        <div class="bottom-actions">
            @if (_inspection.Status == InspectionStatus.InProgress)
            {
                <button class="btn btn-complete" @onclick="CompleteInspection">✓ Complete Inspection</button>
            }
            else
            {
                <div class="completed-banner">✓ Inspection completed</div>
            }
        </div>
    }
</div>

