diff --git a/tmp/sv-358f299904df49fba9b1537ac2701cb0/SiteInspector/SiteInspector.Client/Pages/InspectionDetail.razor b/tmp/sv-358f299904df49fba9b1537ac2701cb0/SiteInspector/SiteInspector.Client/Pages/InspectionDetail.razor
